class DeepLinkHandler {
  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _sub;
  final GlobalKey<NavigatorState> navigatorKey = GlobalKey<NavigatorState>();

  void initialize() {
    _handleInitialUri();
    _handleIncomingLinks();
  }

  Future<void> _handleInitialUri() async {
    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        _processDeepLink(initialUri);
      }
    } on PlatformException {
      // Handle exception
    }
  }

  void _handleIncomingLinks() {
    _sub = uriLinkStream.listen((Uri? uri) {
      if (uri != null) {
        _processDeepLink(uri);
      }
    }, onError: (err) {
      // Handle error
    });
  }

  void _processDeepLink(Uri uri) {
    final path = uri.path;
    final params = uri.queryParameters;

    if (path.startsWith('/profile/')) {
      final userId = path.replaceFirst('/profile/', '');
      _navigateToProfile(userId, params);
    } else if (path == '/payment/confirm') {
      _navigateToPaymentConfirm(params);
    } else if (path.startsWith('/product/')) {
      final productId = path.replaceFirst('/product/', '');
      _navigateToProduct(productId, params);
    } else if (path == '/cart') {
      _navigateToCart(params);
    } else if (path.startsWith('/order/')) {
      final orderId = path.replaceFirst('/order/', '');
      _navigateToOrder(orderId, params);
    } else if (path == '/settings') {
      _navigateToSettings(params);
    } else if (path.startsWith('/category/')) {
      final categoryId = path.replaceFirst('/category/', '');
      _navigateToCategory(categoryId, params);
    } else if (path == '/notification') {
      _navigateToNotification(params);
    } else {
      _navigateToHome();
    }
  }

  void _navigateToProfile(String userId, Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/profile',
      arguments: {
        'userId': userId,
        'params': params,
      },
    );
  }

  void _navigateToPaymentConfirm(Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/payment/confirm',
      arguments: params,
    );
  }

  void _navigateToProduct(String productId, Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/product',
      arguments: {
        'productId': productId,
        'params': params,
      },
    );
  }

  void _navigateToCart(Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/cart',
      arguments: params,
    );
  }

  void _navigateToOrder(String orderId, Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/order',
      arguments: {
        'orderId': orderId,
        'params': params,
      },
    );
  }

  void _navigateToSettings(Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/settings',
      arguments: params,
    );
  }

  void _navigateToCategory(String categoryId, Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/category',
      arguments: {
        'categoryId': categoryId,
        'params': params,
      },
    );
  }

  void _navigateToNotification(Map<String, String> params) {
    navigatorKey.currentState?.pushNamed(
      '/notification',
      arguments: params,
    );
  }

  void _navigateToHome() {
    navigatorKey.currentState?.pushNamedAndRemoveUntil(
      '/',
      (route) => false,
    );
  }

  void dispose() {
    _sub?.cancel();
  }
}

