class MyApp extends StatefulWidget {
  const MyApp({Key? key}) : super(key: key);

  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();

  @override
  void initState() {
    super.initState();
    _deepLinkHandler.initialize();
  }

  @override
  void dispose() {
    _deepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: _deepLinkHandler.navigatorKey,
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      initialRoute: '/',
      onGenerateRoute: (settings) {
        final args = settings.arguments;

        switch (settings.name) {
          case '/':
            return MaterialPageRoute(builder: (_) => HomeScreen());
          case '/profile':
            final arguments = args as Map<String, dynamic>;
            return MaterialPageRoute(
              builder: (_) => ProfileScreen(
                userId: arguments['userId'],
                params: arguments['params'],
              ),
            );
          case '/payment/confirm':
            final params = args as Map<String, String>;
            return MaterialPageRoute(
              builder: (_) => PaymentConfirmScreen(params: params),
            );
          case '/product':
            final arguments = args as Map<String, dynamic>;
            return MaterialPageRoute(
              builder: (_) => ProductScreen(
                productId: arguments['productId'],
                params: arguments['params'],
              ),
            );
          case '/cart':
            final params = args as Map<String, String>? ?? {};
            return MaterialPageRoute(
              builder: (_) => CartScreen(params: params),
            );
          case '/order':
            final arguments = args as Map<String, dynamic>;
            return MaterialPageRoute(
              builder: (_) => OrderScreen(
                orderId: arguments['orderId'],
                params: arguments['params'],
              ),
            );
          case '/settings':
            final params = args as Map<String, String>? ?? {};
            return MaterialPageRoute(
              builder: (_) => SettingsScreen(params: params),
            );
          case '/category':
            final arguments = args as Map<String, dynamic>;
            return MaterialPageRoute(
              builder: (_) => CategoryScreen(
                categoryId: arguments['categoryId'],
                params: arguments['params'],
              ),
            );
          case '/notification':
            final params = args as Map<String, String>? ?? {};
            return MaterialPageRoute(
              builder: (_) => NotificationScreen(params: params),
            );
          default:
            return MaterialPageRoute(builder: (_) => HomeScreen());
        }
      },
    );
  }
}

void main() {
  runApp(MyApp());
}